const jobs = $input.first().json?.data || [];

// Signal category mapping
const signal_map = {
  revops: ['revenue operations', 'revops', 'sales operations'],
  growth: ['head of growth', 'vp growth', 'growth marketing'],
  analytics: ['marketing analytics', 'data analytics', 'business intelligence', 'revenue analytics'],
  cs_scale: ['customer success', 'customer experience', 'cs operations']
};

function getSignalCategory(title) {
  const lower = title.toLowerCase();
  for (const [cat, keywords] of Object.entries(signal_map)) {
    if (keywords.some(k => lower.includes(k))) return cat;
  }
  return null;
}

// Filter to ICP companies and map signal categories
const filtered = jobs
  .map(job => ({
    company_name: job.employer_name,
    company_domain: job.employer_website?.replace(/https?:\/\/(www\.)?/, '').split('/')[0],
    job_title: job.job_title,
    job_url: job.job_apply_link,
    signal_category: getSignalCategory(job.job_title || ''),
    posted_at: job.job_posted_at_datetime_utc,
    location: job.job_city + ', ' + job.job_country
  }))
  .filter(j => j.signal_category && j.company_domain);

return filtered.map(j => ({ json: j }));

const org = $json.organization || {};
const job = $('Filter Intent Signals').item.json;

// ICP validation
const employees = org.estimated_num_employees || 0;
const icp_fit = employees >= 30 && employees <= 1000;
if (!icp_fit) return { json: { skip: true } };

return {
  json: {
    company_name: job.company_name,
    company_domain: job.company_domain,
    company_size: employees,
    industry: org.industry || '',
    tech_stack: (org.technologies || []).slice(0,8).map(t=>t.name).join(', '),
    funding: org.funding_events?.[0]?.currency_raised_in_millions ? `$${org.funding_events[0].currency_raised_in_millions}M` : '',
    job_title: job.job_title,
    job_url: job.job_url,
    signal_category: job.signal_category,
    posted_at: job.posted_at
  }
};

